```
void LayeredTexture::fillTexture(const Document& doc)

{

    const std::vector<const Connection*>& conns = doc.GetConnectionsByDestinationSequenced(ID());
    for(size_t i = 0; i < conns.size();++i)
    {
       const Connection* con = conns.at(i);
